sql:
SELECT COUNT(*) AS tract_count
FROM tracts
WHERE region = 'Metropolitan Area';

SELECT COUNT(*) AS total_parcels
FROM parcels
WHERE tract_id = 123;

SELECT AVG(population_density) AS average_population_density
FROM demographics
WHERE year = 2022;

SELECT tract_id, COUNT(parcel_id) AS total_parcels
FROM parcels
GROUP BY tract_id;

SELECT year, SUM(market_value) AS total_market_value
FROM historical_values
GROUP BY year;

external_knowledge:
- "More valuable" refers to parcels with an average market value higher than the overall average market value;
- "Recent acquisition" means the parcels were acquired after the year 2010;
- "Growing population" indicates a tract's average population greater than the overall average population.

sql:
SELECT year, AVG(sheets) AS avg_sheets
FROM tracts
GROUP BY year;
